171	  const bridgeWsUrl = window.desktopBridge?.getWsUrl?.();
172	  const envWsUrl = import.meta.env.VITE_WS_URL as string | undefined;
173	  const wsCandidate =
174	    typeof bridgeWsUrl === "string" && bridgeWsUrl.length > 0
