312	export function markThreadUnread(state: AppState, threadId: ThreadId): AppState {
313	  const threads = updateThread(state.threads, threadId, (thread) => {
314	    if (!thread.latestTurn?.completedAt) return thread;
315	    const latestTurnCompletedAtMs = Date.parse(thread.latestTurn.completedAt);
316	    if (Number.isNaN(latestTurnCompletedAtMs)) return thread;
317	    const unreadVisitedAt = new Date(latestTurnCompletedAtMs - 1).toISOString();
318	    if (thread.lastVisitedAt === unreadVisitedAt) return thread;
319	    return { ...thread, lastVisitedAt: unreadVisitedAt };
320	  });
321	  return threads === state.threads ? state : { ...state, threads };
322	}
