import { useCallback, useEffect, useSyncExternalStore } from "react";
import {
  DEFAULT_THEME_ID,
  getTheme,
  listThemes,
  type Theme,
} from "@t3tools/shared/themes";

const STORAGE_KEY = "t3code:custom-theme";

/** CSS custom property names mapped from ThemeColors keys. */
const COLOR_PROPERTY_MAP: Record<string, string> = {
  background: "--t3-theme-background",
  foreground: "--t3-theme-foreground",
  accent: "--t3-theme-accent",
  sidebar: "--t3-theme-sidebar",
  editor: "--t3-theme-editor",
  terminal: "--t3-theme-terminal",
  statusBar: "--t3-theme-status-bar",
};

// ---------------------------------------------------------------------------
// External store (same pattern as useTheme.ts)
// ---------------------------------------------------------------------------

let listeners: Array<() => void> = [];
let lastSnapshot: Theme | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

function getStoredId(): string {
  return localStorage.getItem(STORAGE_KEY) ?? DEFAULT_THEME_ID;
}

function applyTheme(theme: Theme) {
  const root = document.documentElement;
  for (const [key, property] of Object.entries(COLOR_PROPERTY_MAP)) {
    root.style.setProperty(property, theme.colors[key as keyof typeof theme.colors]);
  }
  root.style.setProperty("--t3-theme-font-family", theme.fontFamily);
  root.style.setProperty("--t3-theme-font-size", `${String(theme.fontSize)}px`);
}

// Apply immediately on module load to prevent flash.
applyTheme(getTheme(getStoredId()));

function getSnapshot(): Theme {
  const theme = getTheme(getStoredId());

  // Referential stability — only create a new object when the id changes.
  if (lastSnapshot && lastSnapshot.id === theme.id) {
    return lastSnapshot;
  }
  lastSnapshot = theme;
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Cross-tab synchronisation via storage events.
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      applyTheme(getTheme(getStoredId()));
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    window.removeEventListener("storage", handleStorage);
  };
}

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

const availableThemes: readonly Theme[] = listThemes();

export function useCustomTheme() {
  const theme = useSyncExternalStore(subscribe, getSnapshot);

  const setTheme = useCallback((id: string) => {
    const next = getTheme(id);
    localStorage.setItem(STORAGE_KEY, next.id);
    applyTheme(next);
    emitChange();
  }, []);

  // Keep CSS custom properties in sync after hydration / hot-reload.
  useEffect(() => {
    applyTheme(theme);
  }, [theme]);

  return { theme, setTheme, availableThemes } as const;
}

