/** Shared theme definitions consumed by web and desktop apps. */

export interface ThemeColors {
  background: string;
  foreground: string;
  accent: string;
  sidebar: string;
  editor: string;
  terminal: string;
  statusBar: string;
}

export interface Theme {
  id: string;
  name: string;
  colors: ThemeColors;
  fontFamily: string;
  fontSize: number;
}

const BUILT_IN_THEMES: readonly Theme[] = [
  {
    id: "t3-dark",
    name: "T3 Dark",
    colors: {
      background: "#0a0a0a",
      foreground: "#e5e5e5",
      accent: "#6366f1",
      sidebar: "#111111",
      editor: "#0a0a0a",
      terminal: "#0c0c0c",
      statusBar: "#111111",
    },
    fontFamily: '"DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif',
    fontSize: 14,
  },
  {
    id: "t3-light",
    name: "T3 Light",
    colors: {
      background: "#ffffff",
      foreground: "#1a1a1a",
      accent: "#4f46e5",
      sidebar: "#f5f5f5",
      editor: "#ffffff",
      terminal: "#fafafa",
      statusBar: "#f0f0f0",
    },
    fontFamily: '"DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif',
    fontSize: 14,
  },
  {
    id: "t3-midnight",
    name: "T3 Midnight",
    colors: {
      background: "#020617",
      foreground: "#e2e8f0",
      accent: "#8b5cf6",
      sidebar: "#0f172a",
      editor: "#020617",
      terminal: "#0f172a",
      statusBar: "#1e293b",
    },
    fontFamily: '"DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif',
    fontSize: 14,
  },
] as const;

const THEME_MAP = new Map<string, Theme>(BUILT_IN_THEMES.map((t) => [t.id, t]));

/** Default theme id applied when no theme has been selected. */
export const DEFAULT_THEME_ID = "t3-dark";

/** Return the theme matching `id`, or the default theme when `id` is unknown. */
export function getTheme(id: string): Theme {
  return THEME_MAP.get(id) ?? THEME_MAP.get(DEFAULT_THEME_ID)!;
}

/** Return every registered built-in theme. */
export function listThemes(): readonly Theme[] {
  return BUILT_IN_THEMES;
}

