import type { Theme } from "@t3tools/shared/themes";

import { useCustomTheme } from "../hooks/useCustomTheme";

/** A small colour swatch that previews the key surfaces of a theme. */
function ThemeSwatch({ colors }: { colors: Theme["colors"] }) {
  return (
    <div
      className="flex h-7 w-12 shrink-0 overflow-hidden rounded-md border border-border"
      aria-hidden="true"
    >
      <div className="flex-1" style={{ backgroundColor: colors.sidebar }} />
      <div className="flex flex-[2] flex-col">
        <div className="flex-1" style={{ backgroundColor: colors.editor }} />
        <div className="h-1.5" style={{ backgroundColor: colors.statusBar }} />
      </div>
    </div>
  );
}

export function ThemeSelector() {
  const { theme: currentTheme, setTheme, availableThemes } = useCustomTheme();

  return (
    <div className="space-y-2" role="radiogroup" aria-label="Custom theme">
      {availableThemes.map((t) => {
        const selected = currentTheme.id === t.id;
        return (
          <button
            key={t.id}
            type="button"
            role="radio"
            aria-checked={selected}
            className={`flex w-full items-center gap-3 rounded-lg border px-3 py-2 text-left transition-colors ${
              selected
                ? "border-primary/60 bg-primary/8 text-foreground"
                : "border-border bg-background text-muted-foreground hover:bg-accent"
            }`}
            onClick={() => setTheme(t.id)}
          >
            <ThemeSwatch colors={t.colors} />
            <span className="flex flex-1 flex-col">
              <span className="text-sm font-medium">{t.name}</span>
              <span className="text-xs">
                {t.fontFamily.split(",")[0]?.replaceAll('"', "").trim()},{" "}
                {String(t.fontSize)}px
              </span>
            </span>
            {selected ? (
              <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                Active
              </span>
            ) : null}
          </button>
        );
      })}
    </div>
  );
}
